DistribuiÃ§Ã£o por Tipo de EvasÃ£o


chart = {
  const width = 550
  const height = width * 0.5; // MantÃ©m proporÃ§Ã£o
  const radius = Math.min(width, height) / 2 - 10;
  const colorInterpolator = d3.interpolateGreys;

  // Preparar dados
  const dataEvasao = Array.from(
    d3.rollup(
      dados_filtrados,
      v =&gt; d3.sum(v, d =&gt; d.QTDE),
      d =&gt; d.FORMA_EVASAO
    ),
    ([tipo, total]) =&gt; ({ tipo, total })
  ).filter(d =&gt; d.total &gt; 0)
   .sort((a, b) =&gt; d3.descending(a.total, b.total));

  const domain = dataEvasao.map(d =&gt; d.tipo)

  const color = d3.scaleOrdinal()
      .domain(domain)
      .range(d3.quantize(t =&gt; colorInterpolator(t * 0.75 + 0.1 ), domain.length).reverse()) 

  const svg = d3.create("svg")
      .attr("width", width)
      .attr("height", height);

  const g = svg.append("g")
      .attr("transform", `translate(${radius + 50}, ${height / 1.3})`);

  const pie = d3.pie()
      .value(d =&gt; d.total)
      .sort(null);

  const arc = d3.arc()
      .innerRadius(radius * 0.6)
      .outerRadius(radius);

  const arcs = pie(dataEvasao);

  // Desenhar arcos
  const paths = g.selectAll("path")
      .data(arcs)
    .join("path")
      .attr("fill", d =&gt; color(d.data.tipo))
      .attr("d", arc)
      .attr("stroke", "#fff")
      .attr("stroke-width", 2)
      .style("opacity", 0.8)
      .style("cursor", "pointer")
      .each(function(d) { this._current = d; })
      .on("click", function(event, selected) {
      // Clicando na fatia: Destacar a fatia clicada e deixar as outras cinzas
      svg.selectAll("path")
        .transition().duration(200)
        .attr("fill", d =&gt; d.data.tipo === selected.data.tipo ? color(d.data.tipo) : "#D3D3D3"); // "#D3D3D3" Ã© o cinza

      // Se a fatia jÃ¡ estiver selecionada, desmarque
      const isSelected = d3.select(this).classed("selected");
      if (isSelected) {
        d3.select(this).classed("selected", false);
        svg.selectAll("path")
          .transition().duration(200)
          .attr("fill", d =&gt; color(d.data.tipo));  // Voltar Ã s cores originais
      } else {
        d3.select(this).classed("selected", true)
          .transition().duration(200)
          .attr("fill", color(selected.data.tipo));  // Destacar a fatia selecionada
      }
    });

  // Legenda
  const legend = svg.append("g")
      .attr("transform", `translate(${radius * 2 + 100}, 1)`);

  const legendItems = legend.selectAll(".legend-item")
      .data(dataEvasao)
    .join("g")
      .attr("class", "legend-item")
      .attr("transform", (d, i) =&gt; `translate(0, ${i * 25})`)
      .style("cursor", "pointer")
      .on("click", function(event, d) {
        const isActive = d3.select(this).classed("active");
        d3.select(this).classed("active", !isActive);

        const targetOpacity = isActive ? 0.8 : 0.2;
        paths.filter(path =&gt; path.data.tipo === d.tipo)
            .transition().duration(300)
            .style("opacity", targetOpacity);
      });

  legendItems.append("rect")
      .attr("width", 20)
      .attr("height", 20)
      .attr("fill", d =&gt; color(d.tipo))
      .attr("rx", 3);

  legendItems.append("text")
      .attr("x", 25)
      .attr("y", 9)
      .attr("dy", "0.35em")
      .style("font-size", "12px")
      .text(d =&gt; `${d.tipo} (${d.total})`);


  // Tooltip
  const tooltip = d3.select("body").append("div")
      .style("position", "absolute")
      .style("background", "rgba(0,0,0,0.8)")
      .style("color", "white")
      .style("padding", "8px")
      .style("border-radius", "4px")
      .style("font-size", "12px")
      .style("pointer-events", "none")
      .style("opacity", 0);

  paths.on("mouseover", function(event, d) {
        const percentage = ((d.data.total / d3.sum(dataEvasao, x =&gt; x.total)) * 100).toFixed(1);
        tooltip.style("opacity", 1)
            .html(`&lt;strong&gt;${d.data.tipo}&lt;/strong&gt;&lt;br&gt;${d.data.total} alunos (${percentage}%)`);

        d3.select(this).transition().duration(200)
            .style("opacity", 1)
            .attr("stroke-width", 3);
      })
      .on("mousemove", function(event) {
        tooltip.style("left", (event.pageX + 10) + "px")
            .style("top", (event.pageY - 10) + "px");
      })
      .on("mouseout", function(event, d) {
        tooltip.style("opacity", 0);
        d3.select(this).transition().duration(200)
            .style("opacity", 0.8)
            .attr("stroke-width", 2);
      });

  function updateChart(newData) {
    const newPieData = pie(newData);

    paths.data(newPieData)
        .transition().duration(750)
        .attrTween("d", function(d) {
          const i = d3.interpolate(this._current, d);
          this._current = i(0);
          return t =&gt; arc(i(t));
        });
  }

  return Object.assign(svg.node(), { updateChart });
}

html`
